1	import { NextResponse } from "next/server";
2	import type { NextRequest } from "next/server";
3	import {
4	  createRunProgress,
5	  markRunCompleted,
6	  markRunErrored,
7	  setRunProgress,
8	  updateRunProgress,
9	} from "@/lib/run-progress";
10	import { getScenario } from "@/lib/scenario-manager";
11	import { runScenario } from "@/lib/test-runner";
12	
13	export async function POST(_: NextRequest, { params }: { params: { id: string } }) {
14	  try {
15	    const scenario = getScenario(params.id);
16	
17	    if (!scenario) {
18	      return NextResponse.json({ success: false, error: "Not found" }, { status: 404 });
19	    }
20	
21	    setRunProgress(createRunProgress(scenario, params.id));
22	
23	    const result = await runScenario(scenario, {
24	      onTestCaseStart: async (testCase, testCaseIndex, totalTestCases) => {
25	        updateRunProgress(scenario.id, (current) => ({
26	          ...current,
27	          status: "running",
28	          updatedAt: new Date().toISOString(),
29	          currentTestCaseIndex: testCaseIndex + 1,
30	          currentTestCaseName: testCase.name,
31	          currentStepIndex: 0,
32	          currentStepDescription: undefined,
33	          currentTestCaseTotalSteps: testCase.steps.length,
34	          totalTestCases,
35	          message: `테스트케이스 실행 중: ${testCase.name}`,
36	        }));
37	      },
38	      onStepStart: async (testCase, _testCaseIndex, step, stepIndex) => {
39	        updateRunProgress(scenario.id, (current) => ({
40	          ...current,
41	          updatedAt: new Date().toISOString(),
42	          currentTestCaseName: testCase.name,
43	          currentStepIndex: stepIndex + 1,
44	          currentStepDescription: step.description ?? step.type,
45	          currentTestCaseTotalSteps: testCase.steps.length,
46	          message: `Step 실행 중: ${step.description ?? step.type}`,
47	        }));
48	      },
49	      onStepComplete: async () => {
50	        updateRunProgress(scenario.id, (current) => ({
51	          ...current,
52	          updatedAt: new Date().toISOString(),
53	          completedStepsOverall: Math.min(
54	            current.completedStepsOverall + 1,
55	            current.totalStepsOverall
56	          ),
57	          message: `전체 ${Math.min(
58	            current.completedStepsOverall + 1,
59	            current.totalStepsOverall
60	          )}개 step 완료`,
61	        }));
62	      },
63	    });
64	
65	    markRunCompleted(scenario.id);
66	    return NextResponse.json({ success: true, data: result });
67	  } catch (error) {
68	    markRunErrored(params.id, error instanceof Error ? error.message : String(error));
69	    return NextResponse.json({ success: false, error: String(error) }, { status: 500 });
70	  }
71	}
72

1	import type { RunProgress, Scenario } from "./types.js";
2	
3	const progressStore = new Map<string, RunProgress>();
4	
5	export function createRunProgress(scenario: Scenario, scenarioId = scenario.id): RunProgress {
6	  const totalStepsOverall = scenario.testCases.reduce(
7	    (total, testCase) => total + testCase.steps.length,
8	    0
9	  );
10	  const timestamp = new Date().toISOString();
11	
12	  return {
13	    scenarioId,
14	    scenarioName: scenario.name,
15	    status: "running",
16	    startedAt: timestamp,
17	    updatedAt: timestamp,
18	    totalTestCases: scenario.testCases.length,
19	    currentTestCaseIndex: 0,
20	    totalStepsOverall,
21	    completedStepsOverall: 0,
22	    currentStepIndex: 0,
23	    currentTestCaseTotalSteps: 0,
24	    message: "실행 준비 중",
25	  };
26	}
27	
28	export function setRunProgress(progress: RunProgress) {
29	  progressStore.set(progress.scenarioId, progress);
30	}
31	
32	export function getRunProgress(scenarioId: string): RunProgress | null {
33	  return progressStore.get(scenarioId) ?? null;
34	}
35	
36	export function updateRunProgress(
37	  scenarioId: string,
38	  updater: (current: RunProgress) => RunProgress
39	): RunProgress | null {
40	  const current = progressStore.get(scenarioId);
41	
42	  if (!current) {
43	    return null;
44	  }
45	
46	  const next = updater(current);
47	  progressStore.set(scenarioId, next);
48	  return next;
49	}
50	
51	export function markSnapshotSaving(scenarioId: string) {
52	  return updateRunProgress(scenarioId, (current) => ({
53	    ...current,
54	    status: "savingSnapshot",
55	    updatedAt: new Date().toISOString(),
56	    message: "AS-IS 스냅샷 저장 중",
57	  }));
58	}
59	
60	export function markRunCompleted(scenarioId: string) {
61	  return updateRunProgress(scenarioId, (current) => ({
62	    ...current,
63	    status: "completed",
64	    updatedAt: new Date().toISOString(),
65	    currentTestCaseIndex: current.totalTestCases,
66	    currentStepIndex: current.currentTestCaseTotalSteps,
67	    completedStepsOverall: current.totalStepsOverall,
68	    message: "AS-IS 저장 완료",
69	  }));
70	}
71	
72	export function markRunErrored(scenarioId: string, error: string) {
73	  return updateRunProgress(scenarioId, (current) => ({
74	    ...current,
75	    status: "error",
76	    updatedAt: new Date().toISOString(),
77	    error,
78	    message: "실행 중 오류 발생",
79	  }));
80	}
